#include <bits/stdc++.h>
using namespace std;
const int maxn=1e5+5;
int n,k,c[maxn],sum,ans,siz[maxn],dp[maxn][25],tot;
vector<int> g[maxn];
void dfs(int u,int fa) {
	dp[u][0]=c[u];
	for(auto v:g[u]) {
		if(v==fa) {
			continue;
		}
		dfs(v,u);
		for(int j=1;j<=k;j++){
			dp[u][j]+=dp[v][j-1];
		}
	}
}
void dfs1(int u,int fa) {
	for(auto v:g[u]) {
		if(v==fa) {
			continue;
		}
		vector<int> o(k+1);
		for(int j=0;j<=k;j++){
			o[j]=dp[v][j];
		}
		for(int j=1;j<=k;j++){
			dp[v][j]+=dp[u][j-1];
			if(j>=2){
				dp[v][j]-=o[j-2];
			}
		}
		dfs1(v,u);
	}
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>k;
	for(int i=1; i<n; i++) {
		int u,v;
		cin>>u>>v;
		g[u].emplace_back(v);
		g[v].emplace_back(u);
	}
	for(int i=1;i<=n;i++){
		cin>>c[i];
	}
	dfs(1,0);
	dfs1(1,0);
	for(int i=1; i<=n; i++) {
		int sum=0;
		for(int j=0;j<=k;j++){
			sum+=dp[i][j];
		}
		cout<<sum<<"\n";
	}
	return 0;
}
